/**
 * RegionMapScene — stub that forwards directly to localMap.
 * The region map step has been removed from the navigation flow.
 * Navigation is now: World Map -> Local Map directly.
 *
 * @module RegionMapScene
 */

import SceneManager from '../core/SceneManager.js';
import WorldState from '../world/WorldState.js';
import DebugLog from '../debug/DebugLog.js';

const RegionMapScene = {
  async init(data) {
    const regionId = data?.regionId ?? WorldState.currentRegionId ?? 0;
    WorldState.currentRegionId = regionId;

    const region = WorldState.world?.regions?.find(r => r.id === regionId);
    if (region) {
      WorldState.currentRegionLevel = region.level;
    }

    DebugLog.info(`[world] RegionMapScene: forwarding to localMap; regionId=${regionId}`);
    await SceneManager.transition('localMap', { regionId });
  },

  update() {},

  async destroy() {},
};

export default RegionMapScene;
